var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"자, 줄 서세요. 줄. 할아버지께서 새치기는 나쁜 거라고 하셨어요.","JPN":"さあ、1列にお並びください。お祖父様は割り込みはいけないことだと言っていました。","ENG":"Now, please stand in line. Grandfather said that cutting in line is rude.","TWN":"來，請排好隊，我爺爺說插隊是不好的行為。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"나쁜 아이에게는 얼터니움 리액터를 제일 마지막에 드릴 거예요.","JPN":"悪い子はオルタニウムリアクターをあげるのを一番最後にしますよ。","ENG":"Bad children will be the last to receive their Alternium Reactors.","TWN":"不聽話的小朋友最後才能拿到黑化永恆之金電抗器喔。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니까…… 저걸 장비에 연결하면 엄청 강해진다는 거지?","JPN":"つまり……あれを装備につければすごく強くなるってことよね？","ENG":"So... If I connect this to my gear, it will become incredibly powerful?","TWN":"那個……把這個連接到裝備上就會變超強對吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런 것 같네요. 사장님은 또 어디서 저런 재미있는 걸 만들어 오신 걸까요?","JPN":"そうみたいですね。社長はどこであんなおもしろいものを作って来たんでしょうか？","ENG":"That seems to be the case. Which hat do you think Boss pulled this idea out from?","TWN":"好像是這樣，老闆不知道又從哪弄來這麼有趣的東西？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"사장님? 알파트릭스 회장님이 만든 거 아니었어?","JPN":"社長？　アルファトリックス会長が作ったんじゃないの？","ENG":"Boss? It wasn’t the Alphatrix's President who made this?","TWN":"老闆？這不是阿爾法崔克斯的會長製造的嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아. 물론 대외적으로는 그렇긴 합니다만, 그 재료를 저희 사장님이 공급했다는 이야기가 있더라고요.","JPN":"あ、もちろん対外的にはそうなんですが、あれの材料をうちの社長が提供したという話があってですね。","ENG":"Well, publicly, yes. However, there are rumors that our Boss provided the materials.","TWN":"喔～那是對外的說法啦，我聽說材料是老闆提供的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건 대단하네…… 알파트릭스 같은 대기업에 납품도 다 하고.","JPN":"すごいね……アルファトリックスのような大企業に納品までするなんて。","ENG":"That’s impressive... Supplying to a conglomerate like Alphatrix...","TWN":"這麼厲害喔……還提供阿爾法崔克斯這種大企業材料。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양은 하나 받으셨어요?","JPN":"ミナさんは受け取りましたか？","ENG":"Did you receive one too, Mina?","TWN":"米娜你有拿到嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응? 나?","JPN":"えっ？　私？","ENG":"Huh? Me?","TWN":"嗯？我嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아하하, 아니. 내 장비랑은 호환이 안 된다고 하더라고.","JPN":"あはは、それがさ。私の装備とは合わないんだって。","ENG":"Ah hah hah, no. Apparently it’s not compatible with my gear.","TWN":"哈哈，我沒有欸，她說和我的裝備不相容。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"재고도 얼마 없어서 일단은 알트 소대원부터 지급하기로 했대.","JPN":"在庫も少ないから、とりあえずアルト小隊員から支給することにしたんだって。","ENG":"Also, she doesn’t have a lot of stock, so they’ve decided to equip ALT Squad first.","TWN":"而且庫存也不多，所以就先給阿爾特小隊的人。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"하하! 어떠냐, 이게 바로 얼터니움 리액터란 말씀이야!","JPN":"はは！　どうだ、これがオルタニウムリアクターだ！","ENG":"Ha ha! Take that! This is the Alternium Reactor!","TWN":"哈哈！怎麼樣？這就是黑化永恆之金電抗器！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"이게 있으니까 3종…… 아니지! 4종 침식체도 혼자 상대할 수 있을 것 같다구!","JPN":"これがあれば第3種……いや！　第4種侵食体を相手にしても一人で戦えるぞ！","ENG":"With this, I feel like I can take on a Category 3... No, a Category 4 Corrupted Object by myself!","TWN":"只要有這個，管他是3類……不！就算是4類侵蝕體，我好像都能自己應付欸！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잘은 모르겠지만 보고 있으면 뭔가 찌릿찌릿한 느낌이 드네.","JPN":"よくわからないけれど、見ていると何だかチリチリする感じがするね。","ENG":"I’m not sure about that, but I do get a tingling feeling when I look at it.","TWN":"總覺得好像光是用看的，都有點刺痛的感覺。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"출력이 엄청나서 그런 걸까?","JPN":"出力がすごすぎてそうなのかな？","ENG":"Maybe it’s because of its massive output?","TWN":"是因為輸出太強的關係嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"당연하지! 그럼 강해진 기념으로 화력 테스트나 해 볼까?","JPN":"そうに決まってる！　じゃあ、強くなった記念に火力テストでもしてみようか？","ENG":"Of course that’s why! To commemorate the upgrade, let’s test the puppy out!","TWN":"當然！那就當作是慶祝變強，來測試一下火力吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"정말? 그거 기대되는데.","JPN":"本当？　おもしろそうね。","ENG":"Really? I can’t wait!","TWN":"真的嗎？好期待喔。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"좋았어. 그럼 내가 먼저 갈게.","JPN":"よし。私が先に行く。","ENG":"All right! I’ll go first.","TWN":"好！那我先來！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"후우, 울브즈베인은 이 정도인가?","JPN":"ふう、ウルブズベインはこの程度？","ENG":"Ha... Is this all that Wolvesbane can manage?","TWN":"呼，狼之災禍就只有這樣嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"실전이 아니라 그런지 최대 화력은 안 나오네.","JPN":"実戦じゃないからか、最大火力は出ないのね。","ENG":"Maybe it’s because this isn’t an actual battle, but I can’t seem to reach maximum output.","TWN":"是因為不是實戰嗎？沒有完全發揮火力。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"자, 다음은 네 차례야.","JPN":"じゃ、次はあんたの番。","ENG":"Now it’s your turn.","TWN":"來吧，接下來換你。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"……아, 아니. 관둘란다.","JPN":"……あ、いや。やめとく。","ENG":"...N-nah, I’m out.","TWN":"……呃，還是算了！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"생각해 봤는데 말이지, 역시 힘자랑 같은 건 프로답지 못하다구.","JPN":"考えてみたんだけど、やっぱり力自慢なんてプロらしくないだろ。","ENG":"I’ve thought about it, and showing off isn’t professional behavior.","TWN":"仔細想想，炫耀能力不是一個專業的行為。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"저, 절대 화력이 모자라서 그러는 거 아니다?","JPN":"ぜ、絶対に火力が足りないからとかじゃねぇぞ？","ENG":"I-it’s not because I’m worried about how much firepower I’ll display, okay?","TWN":"我…我可不是因為火力不足才這樣說喔！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래? 아쉽네……. 어느 정도인지 궁금했는데.","JPN":"そう？　残念……どれくらいか気になってたのに。","ENG":"Oh? That’s a shame... I was curious about how strong it would be.","TWN":"是喔？好可惜……真好奇有多強。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 네 말이 맞아. 작전 중에 굳이 힘을 낭비할 필요는 없지.","JPN":"でも、そうよね。作戦中にあえて力を浪費することないよね。","ENG":"However, you have a point. There's no reason to waste our strength during a mission.","TWN":"不過你說的沒錯，作戰中不需要浪費無謂的力氣。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"씨이…….","JPN":"ちっ……","ENG":"Grr...","TWN":"可惡……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그러게 왜 사서 고통 받고 그래?","JPN":"だから、なんで進んで痛い思いをしようとするわけ？","ENG":"Why go biting off more than you can chew?","TWN":"真是的，你幹嘛自討苦吃？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"아니……. 그래도 분명 강해졌다고…….","JPN":"いや……でも確かに強くなったって……","ENG":"I mean... I’m still sure I’ve gotten stronger...","TWN":"可是……是真的有變強啦……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양, 방금 무슨 일 있었나요? 폭발음이 들리던데요.","JPN":"ミナさん、さっき何かあったんですか？　爆発音が聞こえましたが。","ENG":"Mina, did something happen just now? I heard an explosion.","TWN":"米娜，剛剛是怎麼回事？我好像聽到爆炸聲？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"부, 부사장님?","JPN":"ふ、副社長？","ENG":"V-vice President?","TWN":"副…副總？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니, 별건 아니고. 그냥 유진이랑 얼터니움 리액터란 거로 얼마나 강해지나 시험해 보려다가……","JPN":"いや、大したことじゃないよ。シロコとオルタニウムリアクターでどれくらい強くなるのか試してみようとして……","ENG":"No, nothing happened. I was just experimenting with Eujin to see how much stronger the Alternium Reactors really made her...","TWN":"沒事啦，我和劉珍想測試一下黑化永恆之金電抗器有多厲害……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"작전 중에 함부로 발포했다는 건가요? 그러다 사고라도 나면 어쩌려고요?","JPN":"作戦中にむやみに発砲したということですか？　それで事故でも起こしたらどうするつもりですか？","ENG":"Are you saying that you fired without good reason during a mission? What if there had been an accident?","TWN":"在作戰期間隨意發射嗎？萬一發生什麼事怎麼辦？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양도 이제 경력직입니다. 자중하는 법도 배워야 하지 않을까요?","JPN":"ミナさんももうシニア社員です。自重することも必要ではないでしょうか？","ENG":"You are not a rookie anymore, Mina. Isn’t it time that you learned how to exercise caution?","TWN":"米娜，你現在已經不是菜鳥，處事上是否該學著自律一點？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그……. 미안.","JPN":"えっと……ごめん。","ENG":"That’s... I’m sorry...","TWN":"我……對不起。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 위험할 건 전혀 없었어. 여긴 이면세계인 데다가 황무지밖에……","JPN":"でも、危険なことは全然なかったよ。ここは裏世界だし荒れ地しか……","ENG":"But there wasn’t anything dangerous about it. I mean, we’re in Counterside, and there’s nothing but wasteland─","TWN":"可是真的一點也不危險的，畢竟這裡是異界，而且又鳥不生蛋的……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어라? 폭발이 점점 거세지는데요?","JPN":"おや？　爆発がだんだん強まっているみたいですが？","ENG":"Huh? The explosions keep getting stronger.","TWN":"嗯？爆炸聲怎麼越來越劇烈？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"설마 저쪽에 뭔가 중요한 시설이라도 있었던 걸까요?","JPN":"まさか、あっちに何か重要な施設でもあったんでしょうか？","ENG":"Could there have been an important facility or something over there?","TWN":"難道是那邊有什麼重要的設施嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그럴 리가! 정말 저쪽에는 아무것도 없었다니까?","JPN":"そ、そんなはずは！　本当にあっちには何もなかったよ？","ENG":"Th-that’s impossible! I’m telling you that there really wasn’t anything over there!","TWN":"怎…怎麼可能！那邊真的完全沒有東西！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……다들 물러서세요.","JPN":"……皆さん、お下がりください。","ENG":"...Everyone stands back.","TWN":"……全都走開！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"부사장님? 하지만……","JPN":"副社長？　でも……","ENG":"Vice President? But...","TWN":"副總？可是……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"괜찮습니다. 미나 양에게 뭐라고 하는 게 아니니까요.","JPN":"大丈夫です。ミナさんを責めるつもりではありませんから。","ENG":"It’s okay, Mina. I’m not scolding you.","TWN":"沒事，我不是要對你說教。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"애초에 저건 폭발이 아니에요.","JPN":"そもそもあれは爆発ではありません。","ENG":"Those weren’t explosions in the first place.","TWN":"那不是爆炸。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"폭발이 아니라고? 그럼 저 화염과 폭음은 대체 뭐야?","JPN":"爆発じゃない？　じゃああの火炎と爆音は何なの？","ENG":"They’re not explosions? Then what are those flames and explosive sounds?","TWN":"不是爆炸？那那個火焰和爆炸聲是怎麼回事？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"임계점을 돌파한 침식파와 CRF가 공명해서 일으키는 에너지 폭풍 같은 겁니다.","JPN":"臨界点を突破した侵食波とCRFが共鳴して発生する、エネルギーの嵐のようなものです。","ENG":"Those are energy storms caused by Corruption Ray which have exceeded their critical points resonating with CRF.","TWN":"那是突破臨界點的侵蝕波和CRF產生共鳴後，進而引發類似能量爆發的現象。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"말하자면 도플갱어 타입 침식체가 생성되면서 발생하는 각성 붕괴 현상이라고 보면 되겠군요.","JPN":"いうなればドッペルゲンガータイプの侵食体が生成されつつ発生する覚醒崩壊のようなものです。","ENG":"I guess you can say that it's the Awakening Collapse caused when Doppelganger-type Corrupted Objects are created.","TWN":"可以把這視為是二重身類型侵蝕體成形後，伴隨而來的覺醒崩潰現象。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"카운터가 처음으로 자신의 힘을 자각할 때 벌어지는 각성 붕괴 현상 말인가요?","JPN":"カウンターが最初に自身の力に目覚めるときに起こる、覚醒崩壊のことですか？","ENG":"You mean the Awakening Collapse that happens when a Counter first awakens their power?","TWN":"制裁者第一次意識到自己的能力時，發生的覺醒崩潰現象嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 각성 붕괴현상은 저렇게 규모가 크지 않을 텐데요. 예외라면……","JPN":"でも、覚醒崩壊はあんなに大規模ではないはずです。例外は……","ENG":"But that shouldn’t happen on such a large scale... unless...","TWN":"可是覺醒崩潰現象應該不至於規模那麼大，還是有例外……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래요. 예외인 존재가 한 명 있었죠.","JPN":"そう。例外の存在が一人いましたよね。","ENG":"Yes, there was one exception.","TWN":"沒錯，有一個是例外。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇다면 설마…… 도플갱어라는 게……","JPN":"まさか……ドッペルゲンガーというのは……","ENG":"Don’t tell me... The Doppelganger is...","TWN":"該不會……所謂的二重身……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"소대장님! 강력한 침식파 반응이 오비탈 베이스로 접근 중입니다!","JPN":"小隊長！　強力な侵食波反応がオービタルベースに接近中です！","ENG":"Commander! A powerful Corruption Ray response is approaching the Orbital Base!","TWN":"小隊長！強烈的侵蝕波反應正在接近軌道基地！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L23_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"도플갱어 타입 침식체 다수, 그리고…… 식별불가의 개체가 하나!","JPN":"ドッペルゲンガータイプの侵食体多数、それから……識別不能な個体が一体！","ENG":"Multiple Doppelganger-type Corrupted Objects and... one unidentified entity!","TWN":"有多個二重身類型侵蝕體，和……一個無法辨識的個體！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래. 보고 있다.","JPN":"ああ。見ている。","ENG":"Yeah, I see them.","TWN":"嗯，我有看到。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다들 방어선까지 물러나서 오비탈 베이스를 지켜라. 여긴 내가 맡겠다.","JPN":"全員防御線まで下がってオービタルベースを守れ。ここは私が引き受ける。","ENG":"Everybody falls back to the defense line and protect the Orbital Base. I’ll handle this.","TWN":"大家退到防線保護軌道基地，這裡就交給我！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……스승님.","JPN":"……師匠。","ENG":"Master...","TWN":"……師父，"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"주변의 도플갱어들은 다 처리했다고 하지 않으셨나요?","JPN":"周囲のドッペルゲンガーは全部片付けたのではなかったのですか？","ENG":"Didn’t you say that all of the nearby Doppelgangers were dealt with?","TWN":"你不是說附近的二重身都已經處理得一乾二淨嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"수월하게 처리했지. 침식파가 반응하지는 않았을 거다.","JPN":"難もなく片付けたさ。侵食波は反応しなかったはずだ。","ENG":"They were taken care of swiftly. The Corruption Ray wouldn’t have reacted to that.","TWN":"當然是有處理乾淨，應該是侵蝕波沒有反應。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아무래도 저건 우릴 환영하기 위해 미리 준비해 둔 선물인 것 같군.","JPN":"どうやらあれは我々を歓迎するためにあらかじめ用意されたプレゼントのようだな。","ENG":"It seems that those were welcome gifts prepared for us beforehand.","TWN":"那應該是事先準備來要歡迎我們的禮物。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하긴, <color=#ffd34c>그녀</color>의 도플갱어가 그리 쉽게 발생하진 않겠죠.","JPN":"確かに、<color=#ffd34c>彼女</color>のドッペルゲンガーがそんなに簡単に発生するわけがありませんね。","ENG":"I guess you're right. <color=#ffd34c>Her</color> Doppelganger wouldn’t have been created so easily.","TWN":"也是，<color=#ffd34c>她</color>的二重身應該不會那麼容易就產生。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이런 일을 할 수 있는 건……","JPN":"こんなことができるのは……","ENG":"The only way this could have been pulled off is if...","TWN":"要做到這件事……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"인형의 창조자와 타락한 부활의 힘, 그리고……","JPN":"人形の創造者と堕落した復活の力、そして……","ENG":"The Puppet Creator, the Corrupted Power of Resurrection, and...","TWN":"若是木偶的創造者和墮落的復活之力……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양의 클리포트 인자 샘플을 가지고 있는 나유빈이 손을 잡는다면.","JPN":"ミナさんのクリフォトファクターサンプルを持っているイチノセ・カオルが繋がっていたら。","ENG":"Na Yubin, who is in possession of Mina’s Qliphoth Factor, joined forces.","TWN":"以及擁有米娜逆卡巴拉因子樣品的羅瑜斌聯手的話，　"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래요. 만들 수도 있겠군요.","JPN":"そうですね。作り出せるかもしれません。","ENG":"That’s true. That would be enough to create this.","TWN":"那應該就辦得到。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……예전에도 그랬지만 파워 하나는 무식할 정도로군요.","JPN":"……前にもそうでしたが、パワーだけは桁外れですね。","ENG":"...Its power levels are off the charts, just as it had been in the past.","TWN":"……以前也是這麼厲害。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스승님께 저걸 상대하게 두는 건 아무리 저라도 조금 거부감이 느껴지네요.","JPN":"師匠にあれの相手をさせるのは、いくら私でも少々気が咎めます。","ENG":"Even from my standards, leaving you to fight that thing by yourself is a bit unreasonable.","TWN":"再怎麼樣，也不好放師父自己去面對。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"전투준비를 해 두겠습니다. 이 중에서 저걸 상대할 수 있는 건 저와 스승님뿐일 테니까요.","JPN":"戦闘準備をしておきます。この中であれを相手できるのは私と師匠だけですから。","ENG":"I’ll get ready for battle. Among the people here, only you and I are capable of fighting that.","TWN":"我會做好戰鬥準備，畢竟在這些人之中，只有我和師父能夠應付對方。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아니, 내가 맡겠다, 이수연.","JPN":"いや、私が引き受ける、カナミ。","ENG":"No, I’ll handle it, Lee Sooyeon.","TWN":"不需要，我來就好。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"진심으로 하시는 말씀인가요?","JPN":"本気ですか？","ENG":"Are you serious?","TWN":"師父這話是認真的嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"전에도 말했지만 그녀는 죽었어.","JPN":"前にも言ったが、彼女は死んだ。","ENG":"As I mentioned before, she is dead.","TWN":"我說過，她已經死了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"남은 찌꺼기들이 내 마음을 괴롭힐 수 있다는 걸 부정하진 않겠다.","JPN":"そのカスが私の心を苦しめていることは否定しまい。","ENG":"I won’t deny that the remaining residue can still hurt my feelings.","TWN":"我不否認殘渣能夠折磨我的心志。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>저걸</color> 불러낸 자들은 여기서 날 시험하고, 비웃고 싶어하겠지.","JPN":"<color=#ffd34c>あれを</color>呼んだ者はここで私を試し、嘲笑いたいのだろう。","ENG":"Those that summoned <color=#ffd34c>that</color> here probably want to put me to the test and mock me.","TWN":"把<color=#ffd34c>那個</color>召喚出來的傢伙，就是想在這裡試驗我、嘲笑我吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그러고 싶다면 마음대로 하라고 해라.","JPN":"そうしたいなら存分にさせておくさ。","ENG":"If that’s the case, let them do as they please.","TWN":"那就隨他們去吧！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하지만 그런 감정이…… 내 의무를 막을 수는 없다.","JPN":"だがそんな感情に……私の義務を妨害させはしない。","ENG":"These emotions I feel... They won’t stop me from completing my mission.","TWN":"但我的情緒……無法阻止我執行我的義務。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"드래곤 버스터, 최대출력!","JPN":"ドラゴンバスター、最大出力！","ENG":"Dragon Buster, maximum power!","TWN":"屠龍者，最大輸出！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_SKILL_START"},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"간다.","JPN":"行くぞ。","ENG":"Engaging the enemy.","TWN":"去吧！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……유미나!","JPN":"……ヤナギ・ミナ！","ENG":"...Yoo Mina!","TWN":"……劉米娜！"},"stage":{"bg":"BLACK","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};